func TestCalculateDiscount(t *testing.T) {
    tests := []struct {
        name     string
        price    float64
        role     string
        wantDisc float64
    }{
        {name: "premium_20pct", price: 100, role: "premium", wantDisc: 20},
        {name: "standard_no_disc", price: 100, role: "user", wantDisc: 0},
        {name: "zero_price", price: 0, role: "premium", wantDisc: 0},
    }

    for _, tc := range tests {
        t.Run(tc.name, func(t *testing.T) {
            got := CalculateDiscount(tc.price, tc.role)
            if got != tc.wantDisc {
                t.Errorf("CalculateDiscount(%v, %q) = %v, want %v",
                    tc.price, tc.role, got, tc.wantDisc)
            }
        })
    }
}

for _, tc := range tests {
    tc := tc // capture loop variable — required in Go < 1.22
    t.Run(tc.name, func(t *testing.T) {
        t.Parallel()
        // ... test body using tc
    })
}

import (
    "github.com/stretchr/testify/assert"
    "github.com/stretchr/testify/require"
)

func TestGetUser(t *testing.T) {
    user, err := GetUser(ctx, 1)
    require.NoError(t, err)          // stop if error
    require.NotNil(t, user)          // stop if nil (prevents nil deref below)
    assert.Equal(t, "alice", user.Name)
    assert.Equal(t, "admin", user.Role)
}

func assertUserEqual(t *testing.T, want, got *User) {
    t.Helper()
    if want.ID != got.ID || want.Name != got.Name {
        t.Errorf("user mismatch: want %+v, got %+v", want, got)
    }
}
